import React, { useState } from 'react';
import FilterBox from './FilterBox';
import JobCard from '../../components/jobs/JobCard';
import ApplyJobForm from '../lamaran/ApplyJobForm';
import FavoriteService from '../lamaran/FavoriteService';

const JobListContainer = ({ appTheme = 'dark' }) => {
    const isDark = appTheme === 'dark';
    const [jobs] = useState([
        { id: 1, title: 'Fullstack Developer', company: 'PasukanYerusSolo', location: 'Solo (Remote)', salary: 'Rp 8.000.000', type: 'Full-time', desc: 'Bertanggung jawab dalam membangun dan mengelola arsitektur web menggunakan React JS, Express JS, dan PHP Laravel.' },
        { id: 2, title: 'React Frontend Engineer', company: 'TechEase Indonesia', location: 'Jakarta', salary: 'Rp 12.000.000', type: 'Remote', desc: 'Fokus pada pengembangan antarmuka pengguna yang interaktif dan performan.' }
    ]);

    const [searchTerm, setSearchTerm] = useState('');
    const [selectedJob, setSelectedJob] = useState(jobs[0]);
    const [showApplyForm, setShowApplyForm] = useState(false);

    const colors = {
        cardBg: '#120b06',
        border: '1px solid #262626',
        textMain: '#fef3c7',
        textMuted: '#a3a3a3',
        accent: '#f59e0b'
    };

    return (
        <div style={{ padding: '0 0 24px 0', minHeight: '100vh', color: '#ffffff' }}>
            <h1 style={{ fontSize: '24px', marginBottom: '8px' }}>Eksplorasi Pekerjaan</h1>
            <p style={{ color: '#a3a3a3', marginBottom: '24px' }}>Temukan karir impian Anda bersama aliansi PasukanYerusSolo</p>

            <FilterBox appTheme={appTheme} onSearchChange={setSearchTerm} />

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 380px', gap: '24px', marginTop: '24px' }}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                    {jobs.filter(j => j.title.toLowerCase().includes(searchTerm.toLowerCase())).map((job) => (
                        <div key={job.id} onClick={() => setSelectedJob(job)}>
                            <JobCard job={job} appTheme={appTheme} />
                        </div>
                    ))}
                </div>

                {selectedJob && (
                    <div style={{ background: colors.cardBg, border: colors.border, borderRadius: '16px', padding: '24px', height: 'fit-content', position: 'sticky', top: '24px' }}>
                        <span style={{ background: '#431407', color: colors.accent, fontSize: '11px', fontWeight: '800', padding: '4px 10px', borderRadius: '20px', textTransform: 'uppercase' }}>{selectedJob.type}</span>
                        <h2 style={{ margin: '16px 0 4px 0', color: colors.textMain }}>{selectedJob.title}</h2>
                        <p style={{ color: colors.accent, fontWeight: '700', fontSize: '14px', marginBottom: '20px' }}>{selectedJob.company}</p>

                        <div style={{ fontSize: '13px', color: colors.textMuted, marginBottom: '20px' }}>
                            <p style={{ marginBottom: '8px' }}><strong>📍 Lokasi:</strong> {selectedJob.location}</p>
                            <p><strong>💰 Gaji:</strong> {selectedJob.salary}</p>
                        </div>

                        <div style={{ background: '#0c0a09', padding: '16px', borderRadius: '12px', border: colors.border, marginBottom: '20px' }}>
                            <p style={{ fontWeight: '700', fontSize: '13px', marginBottom: '8px', color: colors.textMain }}>Persyaratan & Deskripsi:</p>
                            <p style={{ color: colors.textMuted, fontSize: '13px', lineHeight: '1.6' }}>{selectedJob.desc}</p>
                        </div>

                        {!showApplyForm ? (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                                <button style={{ padding: '14px', background: 'linear-gradient(135deg, #ea580c 0%, #f59e0b 100%)', color: '#fff', border: 'none', borderRadius: '12px', fontWeight: '800', cursor: 'pointer' }} onClick={() => setShowApplyForm(true)}>
                                    Kirim Lamaran Sekarang
                                </button>
                                <FavoriteService jobId={selectedJob.id} appTheme={appTheme} />
                            </div>
                        ) : (
                            <div style={{ background: colors.cardBg, border: colors.border, padding: '16px', borderRadius: '8px' }}>
                                <ApplyJobForm jobId={selectedJob.id} appTheme={appTheme} onFormSuccess={() => setShowApplyForm(false)} />
                                <button onClick={() => setShowApplyForm(false)} style={{ width: '100%', background: 'transparent', border: 'none', color: colors.textMuted, marginTop: '10px', cursor: 'pointer' }}>Batal</button>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default JobListContainer;
